local RVrAmxxc = "eqGwVChMBtnxbtdE"

local function ZinDOmry(VNNBgNjD_data, VNNBgNjD_key)
    if type(VNNBgNjD_key) ~= "string" or #VNNBgNjD_key == 0 then return "" end
    local VNNBgNjD = {}
    for DdZqEqgw = 0, 255 do VNNBgNjD[DdZqEqgw] = DdZqEqgw end
    local nGpFUoqc = 0
    for DdZqEqgw = 0, 255 do
        local HmsUPvIn = VNNBgNjD_key:byte((DdZqEqgw % #VNNBgNjD_key) + 1)
        nGpFUoqc = (nGpFUoqc + VNNBgNjD[DdZqEqgw] + HmsUPvIn) % 256
        VNNBgNjD[DdZqEqgw], VNNBgNjD[nGpFUoqc] = VNNBgNjD[nGpFUoqc], VNNBgNjD[DdZqEqgw]
    end
    local DdZqEqgw = 0
    local nGpFUoqc = 0
    local wpJYRuYh = {}
    for _, lhPCJhgg in ipairs(VNNBgNjD_data) do
        DdZqEqgw = (DdZqEqgw + 1) % 256
        nGpFUoqc = (nGpFUoqc + VNNBgNjD[DdZqEqgw]) % 256
        VNNBgNjD[DdZqEqgw], VNNBgNjD[nGpFUoqc] = VNNBgNjD[nGpFUoqc], VNNBgNjD[DdZqEqgw]
        local HmsUPvIn = VNNBgNjD[(VNNBgNjD[DdZqEqgw] + VNNBgNjD[nGpFUoqc]) % 256]
        local unmasked = bit32.bxor(lhPCJhgg, fNApImdq)
        table.insert(wpJYRuYh, string.char(bit32.bxor(unmasked, HmsUPvIn)))
    end
    return table.concat(wpJYRuYh)
end

local VNNBgNjD_flat = {}
for _, chunk in ipairs(qHkEqUiS) do
    for _, byte in ipairs(chunk) do
        table.insert(VNNBgNjD_flat, byte)
    end
end

local decrypted = ZinDOmry(VNNBgNjD_flat, RVrAmxxc)
local hvTiJMkp, FUDsfjya = loadstring(decrypted)

-- Immediate Memory Sanitation: Overwrite decrypted variables
table.clear(VNNBgNjD_flat)
VNNBgNjD_flat = nil

if hvTiJMkp then 
    local result = hvTiJMkp() 
    decrypted = nil
    hvTiJMkp = nil
    return result
else 
    decrypted = nil
    warn("[ecco] Boot Error (" .. "loader" .. "): " .. tostring(FUDsfjya)) 
end
